create table dirkspzm32.pzm_schicht_perioden (
    sp_woche_nr          number(*, 0) not null enable,
    sp_sa_wot_mo         varchar2(10 char),
    sp_sa_wot_di         varchar2(10 char),
    sp_sa_wot_mi         varchar2(10 char),
    sp_sa_wot_do         varchar2(10 char),
    sp_sa_wot_fr         varchar2(10 char),
    sp_sa_wot_sa         varchar2(10 char),
    sp_sa_wot_so         varchar2(10 char),
    sp_ges_std_pro_wo    number(*, 12),
    sp_sm_name           varchar2(100 char) not null enable,
    created_date         date default sysdate not null enable,
    created_login_id     number(*, 0) default - 1 not null enable,
    last_change_date     date,
    last_change_login_id number(*, 0)
);

alter table dirkspzm32.pzm_schicht_perioden
    add constraint pk_sp primary key ( sp_sm_name,
                                       sp_woche_nr )
        using index enable;


